(function () {
  var pRange = document.getElementById('p-range');
  var pVal = document.getElementById('p-val');
  var rOrch = document.getElementById('r-orch');
  var hOrch = document.getElementById('h-orch');
  var rowMrComp = document.getElementById('row-mr-comp');
  var rMrComp = document.getElementById('r-mrcomp');
  var hMrComp = document.getElementById('h-mrcomp');
  var rProvComp = document.getElementById('r-provcomp');
  var hProvComp = document.getElementById('h-provcomp');
  var rPeriodLabel = document.getElementById('r-period-label');
  var rTotalLabel = document.getElementById('r-total-label');
  var rTotalBig = document.getElementById('r-total-big');
  var rTotalSub = document.getElementById('r-total-sub');
  var btnMonthly = document.getElementById('btn-monthly');
  var btnYearly = document.getElementById('btn-yearly');
  var picker = document.getElementById('picker');

  var TOK_IN = 2500, TOK_OUT = 500;     // tokens per packet
  var ORCH_PER_PACKET = 0.0005;          // $5 / 10K packets
  var period = 'monthly';
  var model = { name: 'Compress-v1', billed: 'memrails', inRate: 1, outRate: 5 };

  var nfInt = new Intl.NumberFormat('en-US');
  var nfMoney = new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD' });
  var nfMoney2 = new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', minimumFractionDigits: 2, maximumFractionDigits: 2 });

  function mult() { return period === 'yearly' ? 12 : 1; }
  function suffix() { return period === 'yearly' ? ' / yr' : ' / mo'; }

  function update() {
    var packets = parseInt(pRange.value, 10);
    var k = mult();

    var mOrch = packets * ORCH_PER_PACKET;
    var mCompression = (packets * TOK_IN / 1e6 * model.inRate) + (packets * TOK_OUT / 1e6 * model.outRate);

    var managed = model.billed === 'memrails';
    var mMrComp = managed ? mCompression : 0;
    var mProvComp = managed ? 0 : mCompression;
    var mMemRails = mOrch + mMrComp;
    var mAllIn = mMemRails + mProvComp;

    pVal.textContent = nfInt.format(packets);

    hOrch.textContent = nfInt.format(packets) + ' packets × $5 / 10K';
    rOrch.textContent = nfMoney2.format(mOrch * k) + suffix();

    hMrComp.textContent = managed ? (model.name + ' · managed') : (model.name + ' · billed by provider');
    rMrComp.textContent = managed ? (nfMoney2.format(mMrComp * k) + suffix()) : '—';
    rowMrComp.style.opacity = managed ? '1' : '0.5';

    hProvComp.textContent = managed ? 'none — managed' : (model.name + ' · your key');
    rProvComp.textContent = nfMoney2.format(mProvComp * k) + suffix();

    rPeriodLabel.textContent = (period === 'yearly' ? 'Annual' : 'Monthly') + ' cost';
    rTotalLabel.textContent = 'All-in — ' + (period === 'yearly' ? 'annual' : 'monthly');
    rTotalBig.innerHTML = nfMoney.format(Math.round(mAllIn * k)) + '<span class="yr">' + suffix() + '</span>';
    rTotalSub.innerHTML = '<span class="mrk">MemRails ' + nfMoney.format(Math.round(mMemRails * k)) + '</span> + '
      + '<span class="prv">provider ' + nfMoney.format(Math.round(mProvComp * k)) + '</span> · '
      + nfMoney.format(Math.round(mAllIn * 12)) + ' / yr';
  }

  function setPeriod(p) {
    period = p;
    btnMonthly.classList.toggle('active', p === 'monthly');
    btnYearly.classList.toggle('active', p === 'yearly');
    update();
  }

  picker.addEventListener('click', function (ev) {
    var btn = ev.target.closest('.model-btn');
    if (!btn) return;
    picker.querySelectorAll('.model-btn').forEach(function (b) { b.classList.remove('active'); });
    btn.classList.add('active');
    model = {
      name: btn.getAttribute('data-name'),
      billed: btn.getAttribute('data-billed'),
      inRate: parseFloat(btn.getAttribute('data-in')),
      outRate: parseFloat(btn.getAttribute('data-out'))
    };
    update();
  });

  pRange.addEventListener('input', update);
  btnMonthly.addEventListener('click', function () { setPeriod('monthly'); });
  btnYearly.addEventListener('click', function () { setPeriod('yearly'); });
  update();
})();

if (window.IntersectionObserver && !window.matchMedia('(prefers-reduced-motion: reduce)').matches) {
  var io = new IntersectionObserver(function (entries) {
    entries.forEach(function (e) { if (e.isIntersecting) { e.target.classList.add('in'); io.unobserve(e.target); } });
  }, { threshold: 0.08, rootMargin: '0px 0px -40px 0px' });
  document.querySelectorAll('.reveal').forEach(function (el) { io.observe(el); });
}
